class OAuth2Client {
  constructor(config) {
    this.clientId = config.clientId;
    this.redirectUri = config.redirectUri;
    this.authorizationEndpoint = config.authorizationEndpoint;
    this.tokenEndpoint = config.tokenEndpoint;
    this.scopes = config.scopes || ['openid', 'profile', 'email'];
    this.state = this.generateState();
    this.codeVerifier = this.generateCodeVerifier();
    this.codeChallenge = this.generateCodeChallenge(this.codeVerifier);
  }

  generateState() {
    return btoa(Math.random().toString(36).substring(2, 15) + Math.random().toString(36).substring(2, 15));
  }

  generateCodeVerifier() {
    const array = new Uint32Array(28);
    crypto.getRandomValues(array);
    return btoa(String.fromCharCode(...array))
      .replace(/\+/g, '-')
      .replace(/\//g, '_')
      .replace(/=/g, '');
  }

  generateCodeChallenge(codeVerifier) {
    const encoder = new TextEncoder();
    const data = encoder.encode(codeVerifier);
    return crypto.subtle.digest('SHA-256', data)
      .then(hash => {
        return btoa(String.fromCharCode(...new Uint8Array(hash)))
          .replace(/\+/g, '-')
          .replace(/\//g, '_')
          .replace(/=/g, '');
      });
  }

  async getAuthorizationUrl() {
    const params = new URLSearchParams({
      response_type: 'code',
      client_id: this.clientId,
      redirect_uri: this.redirectUri,
      scope: this.scopes.join(' '),
      state: this.state,
      code_challenge: await this.codeChallenge,
      code_challenge_method: 'S256'
    });

    return `${this.authorizationEndpoint}?${params.toString()}`;
  }

  async handleCallback(url) {
    const urlObj = new URL(url);
    const params = new URLSearchParams(urlObj.search);
    
    const error = params.get('error');
    if (error) {
      throw new Error(`OAuth error: ${error}`);
    }

    const code = params.get('code');
    const state = params.get('state');

    if (!code || !state || state !== this.state) {
      throw new Error('Invalid OAuth callback');
    }

    return await this.exchangeCodeForToken(code);
  }

  async exchangeCodeForToken(code) {
    const response = await fetch(this.tokenEndpoint, {
      method: 'POST',
      headers: {
        'Content-Type': 'application/x-www-form-urlencoded',
        'Accept': 'application/json'
      },
      body: new URLSearchParams({
        grant_type: 'authorization_code',
        client_id: this.clientId,
        code: code,
        redirect_uri: this.redirectUri,
        code_verifier: this.codeVerifier
      }).toString()
    });

    if (!response.ok) {
      throw new Error(`Token exchange failed: ${response.status}`);
    }

    const tokenData = await response.json();
    
    if (!tokenData.access_token) {
      throw new Error('No access token received');
    }

    this.storeTokens(tokenData);
    return tokenData;
  }

  storeTokens(tokenData) {
    const tokens = {
      accessToken: tokenData.access_token,
      refreshToken: tokenData.refresh_token,
      expiresIn: tokenData.expires_in,
      tokenType: tokenData.token_type,
      expiresAt: Date.now() + (tokenData.expires_in * 1000)
    };

    localStorage.setItem('oauth_tokens', JSON.stringify(tokens));
  }

  getAccessToken() {
    const tokens = localStorage.getItem('oauth_tokens');
    if (!tokens) return null;

    const parsed = JSON.parse(tokens);
    if (Date.now() >= parsed.expiresAt) {
      return null;
    }

    return parsed.accessToken;
  }

  async refreshAccessToken() {
    const tokens = localStorage.getItem('oauth_tokens');
    if (!tokens) throw new Error('No refresh token available');

    const parsed = JSON.parse(tokens);
    if (!parsed.refreshToken) throw new Error('No refresh token available');

    const response = await fetch(this.tokenEndpoint, {
      method: 'POST',
      headers: {
        'Content-Type': 'application/x-www-form-urlencoded',
        'Accept': 'application/json'
      },
      body: new URLSearchParams({
        grant_type: 'refresh_token',
        client_id: this.clientId,
        refresh_token: parsed.refreshToken
      }).toString()
    });

    if (!response.ok) {
      throw new Error(`Token refresh failed: ${response.status}`);
    }

    const tokenData = await response.json();
    this.storeTokens(tokenData);
    return tokenData;
  }

  async makeAuthenticatedRequest(url, options = {}) {
    const accessToken = this.getAccessToken();
    if (!accessToken) {
      throw new Error('No access token available');
    }

    const defaultOptions = {
      headers: {
        'Authorization': `Bearer ${accessToken}`,
        'Accept': 'application/json'
      }
    };

    const finalOptions = { ...defaultOptions, ...options };

    try {
      const response = await fetch(url, finalOptions);
      
      if (response.status === 401) {
        // Token might be expired, try to refresh
        try {
          await this.refreshAccessToken();
          const refreshedAccessToken = this.getAccessToken();
          finalOptions.headers.Authorization = `Bearer ${refreshedAccessToken}`;
          return await fetch(url, finalOptions);
        } catch (refreshError) {
          throw new Error('Authentication required');
        }
      }

      return response;
    } catch (error) {
      throw new Error(`Request failed: ${error.message}`);
    }
  }

  logout() {
    localStorage.removeItem('oauth_tokens');
  }
}

